// Some portions generated by Co-Pilot
import { describe, it, expect } from "vitest";
import { render, screen } from "@testing-library/react";
import WaysToSupport from "../index";

describe("WaysToSupport", () => {
  it("renders the section", () => {
    const { container } = render(<WaysToSupport />);
    expect(container.querySelector("section")).toBeInTheDocument();
  });

  it("renders the CommonHeading component", () => {
    render(<WaysToSupport />);
    // CommonHeading renders with translated text
    expect(screen.getAllByText("Text").length).toBeGreaterThan(0);
  });

  it("renders support cards", () => {
    render(<WaysToSupport />);
    // Three CommonCard components should be rendered (contribute, sustainers, member)
    const buttons = screen.getAllByRole("button");
    expect(buttons.length).toBeGreaterThanOrEqual(3);
  });

  it("renders links to contribute, sustainers, and join pages", () => {
    render(<WaysToSupport />);
    const links = screen.getAllByRole("link");
    const hrefs = links.map((link) => link.getAttribute("href"));
    expect(hrefs).toContain("/contributing/");
    expect(hrefs).toContain("/sustainers");
    expect(hrefs).toContain("/join");
  });
});
